const snapshots = $input.all().map(item => item.json);
const today = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });

const lines = [];
lines.push(`⚔️ *Weekly Competitive Monitor — ${today}*`);
lines.push(`*${snapshots.length} active competitive alert${snapshots.length !== 1 ? 's' : ''} detected*`);
lines.push('');

for (const snap of snapshots) {
  const competitor = snap.Competitor_Name__c || snap.Name || 'Unknown Competitor';
  const related = snap.Account__c
    ? `Client Account ID: ${snap.Account__c}`
    : snap.Lead__c
    ? `Prospect Lead ID: ${snap.Lead__c}`
    : 'Unknown record';

  const signals = [];
  const delta = snap.Review_Delta__c || 0;
  if (delta >= 5) {
    signals.push(`📈 +${delta} reviews since last snapshot (now ${snap.Google_Review_Count__c || '?'} | ${snap.Google_Star_Rating__c || '?'}⭐)`);
  }
  if (snap.Running_Google_Ads__c) signals.push(`💰 Running Google Ads`);
  if (snap.Running_Facebook_Ads__c) signals.push(`📱 Running Facebook Ads`);
  const mapsPos = snap.Maps_Pack_Position__c;
  if (mapsPos != null && mapsPos >= 1 && mapsPos <= 3) {
    signals.push(`📍 In Google Maps Pack — position ${mapsPos}`);
  }
  const pressure = snap.Competitive_Pressure_Score__c || 0;
  if (pressure >= 75) signals.push(`⚠️ High pressure score: ${pressure}/100`);
  else if (pressure >= 50) signals.push(`🟡 Moderate pressure score: ${pressure}/100`);

  const snapshotDate = snap.Snapshot_Date__c
    ? new Date(snap.Snapshot_Date__c).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
    : 'Unknown';

  lines.push(`*${competitor}*  |  Snapshot: ${snapshotDate}`);
  lines.push(related);
  if (signals.length > 0) {
    signals.forEach(s => lines.push(`  • ${s}`));
  } else {
    lines.push(`  • No specific signal flags — included by pressure score threshold`);
  }
  lines.push('');
}

lines.push(`_Run *sf_get_competitive_alerts* in Prophet for full detail_`);
lines.push(`_Phase 2: Live re-check via SerpAPI coming soon_`);

return [{ json: { message: lines.join('\n'), alertCount: snapshots.length } }];

